import { NextRequest } from 'next/server';
import { registerClient, unregisterClient } from '@/lib/events';

export const dynamic = 'force-dynamic';

export async function GET(req: NextRequest) {
  const clientId = Math.random().toString(36).substring(2, 15);

  const stream = new ReadableStream({
    start(controller) {
      registerClient(clientId, controller);

      // Send initial comment to establish connection and satisfy stream opening
      try {
        controller.enqueue(new TextEncoder().encode(': keepalive\n\n'));
      } catch (e) {
        console.error('[SSE] Failed to enqueue initial keepalive:', e);
      }

      req.signal.addEventListener('abort', () => {
        unregisterClient(clientId);
      });
    },
    cancel() {
      unregisterClient(clientId);
    },
  });

  return new Response(stream, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache, no-transform',
      'Connection': 'keep-alive',
    },
  });
}
